function indicarProdutosNoCarrinhoEFavoritos(){new indicadorNotificacao}class indicadorNotificacao{constructor(){this.indicadorFavorito=document.querySelectorAll(".indicador-favoritos"),this.indicadorCarrinho=document.querySelector(".indicador-carrinho"),this.produtosFavoritos=JSON.parse(localStorage.getItem("meusFavoritos"))||[],this.produtosCarrinho=JSON.parse(localStorage.getItem("produtosCarrinho"))||[],this.verificarProdutosFavoritadosECarrinho()}verificarProdutosFavoritadosECarrinho(){this.produtosFavoritos.length<1?this.indicadorFavorito&&this.indicadorFavorito.forEach(o=>{o.style.display="none"}):this.indicadorFavorito&&this.indicadorFavorito.forEach(o=>{o.style.display="flex"}),this.produtosCarrinho.length<1?this.indicadorCarrinho&&(this.indicadorCarrinho.style.display="none"):this.indicadorCarrinho&&(this.indicadorCarrinho.style.display="flex")}}export{indicarProdutosNoCarrinhoEFavoritos};